#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        double P;
        int X, Y, Z;
        scanf("%lf %d %d %d", &P, &X, &Y, &Z);
        double factor = (Z == 1) ? (1.0 + Y / 100.0) : (1.0 - X / 100.0);
        double result = P * factor;
        printf("%.10f\n", result);
    }
    return 0;
}

